43	
44	#include "src/fastertransformer/utils/logger.h"
45	
46	#if defined(CUDART_VERSION) && CUDART_VERSION < 11020
47	#define CUDA_MEMORY_POOL_DISABLED
48	#endif
49	
50	namespace fastertransformer {
51	
52	enum class AllocatorType {
53	    CUDA,
54	    TF,
55	    TH
56	};
57	
58	enum class ReallocType {
59	    INCREASE,
60	    REUSE,
61	    DECREASE,
62	};
63	
64	class IAllocator {
65	public:
66	    virtual ~IAllocator(){};
67	
68	    virtual void*        malloc(size_t size, const bool is_set_zero = true, bool is_host = false) = 0;
69	    virtual void         free(void** ptr, bool is_host = false) const                             = 0;
70	    virtual void         setStream(cudaStream_t stream)                                           = 0;
71	    virtual cudaStream_t returnStream()                                                           = 0;
72	    virtual void         memSet(void* ptr, const int val, const size_t size)                      = 0;
73	
74	    template<typename T>
75	    void* reMalloc(T* ptr, size_t size, const bool is_set_zero = true, bool is_host = false)
76	    {
77	        FT_LOG_DEBUG(__PRETTY_FUNCTION__);
78	        size              = ((size + 31) / 32) * 32;  // make the buffer align with 32 bytes
79	        void* void_ptr    = (void*)ptr;
80	        void* ptr_address = getAddress(void_ptr);
81	        if (isExist(ptr_address)) {
82	            ReallocType realloc_type = isReMalloc(ptr_address, size);
83	            if (realloc_type == ReallocType::INCREASE) {
84	                FT_LOG_DEBUG("ReMalloc the buffer %p since it is too small.", void_ptr);
85	                free((void**)(&void_ptr), is_host);
86	                return malloc(size, is_set_zero, is_host);
87	            }
88	#if !defined(CUDA_MEMORY_POOL_DISABLED)
89	            else if (realloc_type == ReallocType::DECREASE) {
90	                FT_LOG_DEBUG("ReMalloc the buffer %p to release unused memory to memory pools.", void_ptr);
91	                free((void**)(&void_ptr), is_host);
92	                return malloc(size, is_set_zero, is_host);
93	            }
94	#endif
95	            else {
96	                FT_LOG_DEBUG("Reuse original buffer %p with size %d and do nothing for reMalloc.", void_ptr, size);
97	                if (is_set_zero) {
98	                    memSet(void_ptr, 0, size);
99	                }
100	                return void_ptr;
101	            }
102	        }
103	        else {
104	            FT_LOG_DEBUG("Cannot find buffer %p, mallocing new one.", void_ptr);
105	            return malloc(size, is_set_zero, is_host);
106	        }
107	    }
108	
109	protected:
110	    virtual bool        isExist(void* address) const                 = 0;
111	    virtual ReallocType isReMalloc(void* address, size_t size) const = 0;
112	
113	    void* getAddress(void* ptr) const
114	    {
115	        return ptr;
116	    }
117	};
118	
119	template<AllocatorType AllocType_>
120	class Allocator;
121	
122	template<>
123	class Allocator<AllocatorType::CUDA>: public IAllocator {
124	private:
125	    const int                          device_id_;
126	    cudaStream_t                       stream_ = 0;  // initialize as default stream
127	    std::unordered_map<void*, size_t>* pointer_mapping_;
128	
129	    bool isExist(void* address) const
130	    {
131	        return pointer_mapping_->count(address) > 0;
132	    }
133	    ReallocType isReMalloc(void* address, size_t size) const
134	    {
135	        FT_CHECK(isExist(address));
136	        if (pointer_mapping_->at(address) < size) {
137	            return ReallocType::INCREASE;
138	        }
139	        else if (pointer_mapping_->at(address) == size) {
140	            return ReallocType::REUSE;
141	        }
142	        else {
143	            return ReallocType::DECREASE;
144	        }
145	    }
146	
147	public:
148	    Allocator(int device_id): device_id_(device_id)
149	    {
150	        FT_LOG_DEBUG(__PRETTY_FUNCTION__);
151	        pointer_mapping_ = new std::unordered_map<void*, size_t>();
152	#if defined(CUDA_MEMORY_POOL_DISABLED)
153	        FT_LOG_WARNING(
154	            "Async cudaMalloc/Free is not supported before CUDA 11.2. Using Sync cudaMalloc/Free."
155	            "Note this may lead to hang with NCCL kernels launched in parallel; if so, try NCCL_LAUNCH_MODE=GROUP");
156	#else
157	        int device_count = 1;
158	        check_cuda_error(cudaGetDeviceCount(&device_count));
159	        cudaMemPool_t mempool;
160	        check_cuda_error(cudaDeviceGetDefaultMemPool(&mempool, device_id));
161	        cudaMemAccessDesc desc                  = {};
162	        int               peer_access_available = 0;
163	        for (int i = 0; i < device_count; i++) {
164	            if (i == device_id) {
165	                continue;
166	            }
167	            check_cuda_error(cudaDeviceCanAccessPeer(&peer_access_available, device_id, i));
168	            if (!peer_access_available) {
169	                FT_LOG_WARNING("Device " + std::to_string(device_id) + " peer access Device " + std::to_string(i)
170	                               + " is not available.");
171	                continue;
172	            }
173	            desc.location.type = cudaMemLocationTypeDevice;
174	            desc.location.id   = i;
175	            desc.flags         = cudaMemAccessFlagsProtReadWrite;
176	            check_cuda_error(cudaMemPoolSetAccess(mempool, &desc, 1));
177	        }
178	        // set memory pool threshold to avoid shrinking the pool
179	        uint64_t setVal = UINT64_MAX;
180	        check_cuda_error(cudaMemPoolSetAttribute(mempool, cudaMemPoolAttrReleaseThreshold, &setVal));
181	#endif
182	    }
183	
184	    virtual ~Allocator()
185	    {
186	        FT_LOG_DEBUG(__PRETTY_FUNCTION__);
187	        while (!pointer_mapping_->empty()) {
188	            free((void**)(&pointer_mapping_->begin()->first));
189	        }
190	        delete pointer_mapping_;
191	    }
192	
193	    void setStream(cudaStream_t stream)
194	    {
195	        stream_ = stream;
196	    }
197	
198	    cudaStream_t returnStream()
199	    {
200	        return stream_;
201	    };
202	
203	    void* malloc(size_t size, const bool is_set_zero = true, bool is_host = false)
204	    {
205	        FT_LOG_DEBUG(__PRETTY_FUNCTION__);
206	        if (size == 0) {
207	            return nullptr;
208	        }
209	        void* ptr      = nullptr;
210	        int   o_device = 0;
211	
212	        check_cuda_error(getSetDevice(device_id_, &o_device));
213	        if (is_host) {
214	            check_cuda_error(cudaMallocHost(&ptr, (size_t)(ceil(size / 32.)) * 32));
215	        }
216	        else {
217	#if defined(CUDA_MEMORY_POOL_DISABLED)
218	            check_cuda_error(cudaMalloc(&ptr, (size_t)(ceil(size / 32.)) * 32));
219	#else
220	            check_cuda_error(cudaMallocAsync(&ptr, (size_t)(ceil(size / 32.)) * 32, stream_));
221	#endif
222	        }
223	        if (is_set_zero) {
224	            check_cuda_error(cudaMemsetAsync(ptr, 0, (size_t)(ceil(size / 32.)) * 32, stream_));
225	        }
226	        check_cuda_error(getSetDevice(o_device));
227	        FT_LOG_DEBUG("malloc buffer %p with size %ld", ptr, size);
228	
229	        pointer_mapping_->insert({getAddress(ptr), size});
230	
231	        return ptr;
232	    }
233	
234	    void free(void** ptr, bool is_host = false) const
235	    {
236	        FT_LOG_DEBUG(__PRETTY_FUNCTION__);
237	        void* address = getAddress(*ptr);
238	        if (*ptr != nullptr) {
239	            int o_device = 0;
240	            if (pointer_mapping_->count(address)) {
241	                FT_LOG_DEBUG("Free buffer %p", address);
242	                check_cuda_error(getSetDevice(device_id_, &o_device));
243	                if (is_host) {
244	                    check_cuda_error(cudaFreeHost(*ptr));
245	                }
246	                else {
247	#if defined(CUDA_MEMORY_POOL_DISABLED)
248	                    check_cuda_error(cudaFree(*ptr));
249	#else
250	                    check_cuda_error(cudaFreeAsync(*ptr, stream_));
251	                    cudaStreamSynchronize(stream_);
252	#endif
253	                }
254	                check_cuda_error(getSetDevice(o_device));
255	                pointer_mapping_->erase(address);
256	            }
257	            else {
258	                FT_LOG_WARNING("pointer_mapping_ does not have information of ptr at %p.", address);
259	            }
260	        }
261	        *ptr = nullptr;
262	        return;
263	    }
264	
265	    void memSet(void* ptr, const int val, const size_t size)
266	    {
267	        check_cuda_error(cudaMemsetAsync(ptr, val, size, stream_));
268	    }
269	};
270	
271	#ifdef GOOGLE_CUDA
272	using namespace tensorflow;
273	template<>
274	class Allocator<AllocatorType::TF>: public IAllocator {
275	    OpKernelContext*                               context_;
276	    std::unordered_map<void*, tensorflow::Tensor>* pointer_mapping_;
277	    cudaStream_t                                   stream_;
278	
279	    bool isExist(void* address) const
280	    {
281	        return pointer_mapping_->count(address) > 0;
282	    }
283	    ReallocType isReMalloc(void* address, size_t size) const
284	    {
285	        FT_CHECK(isExist(address));
286	        size_t current_buffer_size = 1;
287	        for (int i = 0; i < pointer_mapping_->at(address).dims(); i++) {
288	            current_buffer_size *= pointer_mapping_->at(address).dim_size(i);
289	        }
290	        FT_LOG_DEBUG("current_buffer_size: %d, new buffer: %d", current_buffer_size, size);
291	        if (current_buffer_size < size) {
292	            return ReallocType::INCREASE;
293	        }
294	        else if (current_buffer_size == size) {
295	            return ReallocType::REUSE;
296	        }
297	        else {
298	            return ReallocType::DECREASE;
299	        }
300	    }
301	
302	public:
303	    Allocator(OpKernelContext* context, cudaStream_t stream): context_(context), stream_(stream)
304	    {
305	        pointer_mapping_ = new std::unordered_map<void*, tensorflow::Tensor>();
306	    }
307	
308	    void setStream(cudaStream_t stream)
309	    {
310	        stream_ = stream;
311	    }
312	
313	    cudaStream_t returnStream()
314	    {
315	        return stream_;
316	    };
317	
318	    void* malloc(size_t size, const bool is_set_zero = true, bool is_host = false)
319	    {
320	        FT_LOG_DEBUG(__PRETTY_FUNCTION__);
321	        tensorflow::Tensor buf;
322	        long long int      buf_size = ((long long int)ceil(size / 32.) * 32);
323	        tensorflow::Status status;
324	        if (is_host) {
325	            tensorflow::AllocatorAttributes pinned_allocator;
326	            pinned_allocator.set_on_host(true);
327	            pinned_allocator.set_gpu_compatible(true);
328	            status = context_->allocate_temp(DT_UINT8, TensorShape{buf_size}, &buf, pinned_allocator);
329	        }
330	        else {
331	            status = context_->allocate_temp(DT_UINT8, TensorShape{buf_size}, &buf);
332	        }
333	
334	        if (status != tensorflow::Status::OK()) {
335	            throw std::runtime_error("TF error: context->allocate_temp failed");
336	        }
337	
338	        auto  flat = buf.flat<uint8>();
339	        void* ptr  = (void*)flat.data();
340	        if (is_set_zero) {
341	            cudaMemsetAsync(ptr, 0, buf_size, stream_);
342	        }
343	        pointer_mapping_->insert({getAddress(ptr), buf});
344	
345	        return ptr;
346	    }
347	
348	    void free(void** ptr, bool is_host = false) const
349	    {
350	        FT_LOG_DEBUG(__PRETTY_FUNCTION__);
351	        void* address = getAddress(*ptr);
352	        pointer_mapping_->erase(address);
353	        *ptr = nullptr;
354	        return;
355	    }
356	
357	    virtual ~Allocator()
358	    {
359	        while (!pointer_mapping_->empty()) {
360	            void* ptr = pointer_mapping_->begin()->second.flat<uint8>().data();
361	            free((void**)(&ptr));
362	        }
363	        pointer_mapping_->clear();
364	        delete pointer_mapping_;
365	    }
366	
367	    void memSet(void* ptr, const int val, const size_t size)
368	    {
369	        check_cuda_error(cudaMemsetAsync(ptr, val, size, stream_));
370	    }
371	};
372	#endif
373	
374	#ifdef TORCH_CUDA
375	template<>
376	class Allocator<AllocatorType::TH>: public IAllocator {
377	    std::unordered_map<void*, torch::Tensor>* pointer_mapping_;
378	
379	    bool isExist(void* address) const
380	    {
381	        return pointer_mapping_->count(address) > 0;
382	    }
383	    ReallocType isReMalloc(void* address, size_t size) const
384	    {
385	        FT_CHECK(isExist(address));
386	        size_t current_buffer_size = 1;
387	        for (int i = 0; i < pointer_mapping_->at(address).dim(); i++) {
388	            current_buffer_size *= pointer_mapping_->at(address).size(i);
389	        }
390	        FT_LOG_DEBUG(
391	            "current_buffer_size: %d, original buffer: %p, new buffer: %d", current_buffer_size, address, size);
392	        if (current_buffer_size < size) {
393	            return ReallocType::INCREASE;
394	        }
395	        else if (current_buffer_size == size) {
396	            return ReallocType::REUSE;
397	        }
398	        else {
399	            return ReallocType::DECREASE;
400	        }
401	    }
402	
403	public:
404	    Allocator()
405	    {
406	        pointer_mapping_ = new std::unordered_map<void*, torch::Tensor>();
407	    }
408	
409	    void setStream(cudaStream_t stream)
410	    {
411	        // nothing to do here;
412	    }
413	
414	    cudaStream_t returnStream()
415	    {
416	        // nothing to do here;
417	        return 0;
418	    };
419	
420	    void* malloc(size_t size, const bool is_set_zero = true, bool is_host = false)
421	    {
422	        FT_LOG_DEBUG(__PRETTY_FUNCTION__);
423	        int64_t       buf_size = static_cast<int64_t>(ceil(size / 32.)) * 32;
424	        torch::Tensor buf;
425	        if (is_host) {
426	            buf = torch::empty({buf_size}, torch::dtype(torch::kUInt8).device(torch::kCPU).pinned_memory(true));
427	        }
428	        else {
429	            buf = torch::empty({buf_size}, torch::dtype(torch::kUInt8).device(torch::kCUDA));
430	        }
431	        void* ptr = buf.data_ptr();
432	        if (is_set_zero) {
433	            cudaMemset(ptr, 0, buf_size);
434	        }
435	        FT_LOG_DEBUG("malloc buffer %p with size %ld", ptr, buf_size);
436	        pointer_mapping_->insert({getAddress(ptr), buf});
437	        return ptr;
438	    }
439	
440	    void free(void** ptr, bool is_host = false) const
441	    {
442	        FT_LOG_DEBUG(__PRETTY_FUNCTION__);
443	        void* address = getAddress(*ptr);
444	        pointer_mapping_->erase(address);
445	        *ptr = nullptr;
446	        return;
447	    }
448	
449	    virtual ~Allocator()
450	    {
451	        FT_LOG_DEBUG(__PRETTY_FUNCTION__);
